#include <cstdio>
#include <cstdlib>
#include <cuda_runtime.h>

#define INF 1000000

__global__ void floydwarshall_kernel(int* dist, int k, int n) {
    int i = blockIdx.y * blockDim.y + threadIdx.y;
    int j = blockIdx.x * blockDim.x + threadIdx.x;

    if (i < n && j < n) {
        int ik = dist[i * n + k];
        int kj = dist[k * n + j];
        int ij = dist[i * n + j];
        if (ik + kj < ij) {
            dist[i * n + j] = ik + kj;
        }
    }
}

int main(int argc, char* argv[]) {
    if (argc != 2) {
        printf("Usage: %s <matrix_size>\n", argv[0]);
        return 1;
    }

    int n = atoi(argv[1]);
    int size = n * n;
    int* h_dist = (int*)malloc(size * sizeof(int));
    if (!h_dist) {
        fprintf(stderr, "Host memory allocation failed\n");
        return 1;
    }

    // Initialize the distance matrix
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (i == j)
                h_dist[i * n + j] = 0;
            else
                h_dist[i * n + j] = rand() % 20 + 1;
        }
    }

    int* d_dist;
    cudaMalloc(&d_dist, size * sizeof(int));
    cudaMemcpy(d_dist, h_dist, size * sizeof(int), cudaMemcpyHostToDevice);

    dim3 blockDim(32, 32);
    dim3 gridDim((n + blockDim.x - 1) / blockDim.x,
                 (n + blockDim.y - 1) / blockDim.y);

    for (int k = 0; k < n; k++) {
        floydwarshall_kernel<<<gridDim, blockDim>>>(d_dist, k, n);
        cudaDeviceSynchronize();
    }

    cudaMemcpy(h_dist, d_dist, size * sizeof(int), cudaMemcpyDeviceToHost);

    // Print the resulting distance matrix
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (h_dist[i * n + j] >= INF)
                printf("INF ");
            else
                printf("%d ", h_dist[i * n + j]);
        }
        printf("\n");
    }

    cudaFree(d_dist);
    free(h_dist);

    return 0;
}
